  1	import * as React from 'react';
  2	import { Table, Tbody, Td, Th, Thead, ThProps, Tr } from '@patternfly/react-table';
  3	import { kialiStyle } from 'styles/StyleUtils';
  4	import { PFColors } from '../../../components/Pf/PfColors';
  5	import { Button, ButtonVariant } from '@patternfly/react-core';
  6	import { Listener } from '../../../types/IstioObjects';
  7	import { ListenerForm } from '../K8sGatewayForm';
  8	import {
  9	  ListenerBuilder,
 10	  allowedRoutes,
 11	  protocols,
 12	  tlsModes,
 13	  protocolsCert,
 14	  TERMINATE,
 15	  SELECTOR
 16	} from './ListenerBuilder';
 17	import { KialiIcon } from 'config/KialiIcon';
 18	
 19	type ListenerListProps = {
 20	  listeners: Listener[];
 21	  listenersForm: ListenerForm[];
 22	  onChange: (listener: Listener[], listenerForm: ListenerForm[]) => void;
 23	};
 24	
 25	const noListenerStyle = kialiStyle({
 26	  color: PFColors.Red100,
 27	  textAlign: 'center'
 28	});
 29	
 30	const addListenerStyle = kialiStyle({
 31	  marginLeft: '0.5rem',
 32	  marginTop: '0.25rem'
 33	});
 34	
 35	const columns: ThProps[] = [
 36	  {
 37	    title: 'Name',
 38	    width: 20
 39	  },
 40	  {
 41	    title: 'Hostname',
 42	    width: 20
 43	  },
 44	  {
 45	    title: 'Port',
 46	    width: 10
 47	  },
 48	  {
 49	    title: 'Protocol',
 50	    width: 10
 51	  },
 52	  {
 53	    title: 'From Namespaces',
 54	    width: 10
 55	  },
 56	  {
 57	    title: 'Labels',
 58	    width: 25
 59	  },
 60	  {
 61	    title: '',
 62	    width: 10
 63	  }
 64	];
 65	
 66	export const addSelectorLabels = (value: string): [boolean, {}] => {
 67	  if (value.length === 0) {
 68	    return [false, {}];
 69	  }
 70	
 71	  let result = true;
 72	  value = value.trim();
 73	  const labels: string[] = value.split(',');
 74	
 75	  const selector: { [key: string]: string } = {};
 76	
 77	  // Some smoke validation rules for the labels
 78	  for (let i = 0; i < labels.length; i++) {
 79	    const label = labels[i];
 80	    if (label.indexOf('=') < 0) {
 81	      result = false;
 82	      break;
 83	    }
 84	
 85	    const splitLabel: string[] = label.split('=');
 86	    if (splitLabel.length !== 2) {
 87	      result = false;
 88	      break;
 89	    }
 90	
 91	    if (splitLabel[0].trim().length === 0 || splitLabel[1].trim().length === 0) {
 92	      result = false;
 93	      break;
 94	    }
 95	
 96	    selector[splitLabel[0].trim()] = splitLabel[1].trim();
 97	  }
 98	
 99	  return [result, selector];
100	};
101	
102	export const ListenerList: React.FC<ListenerListProps> = (props: ListenerListProps) => {
103	  const onAddListener = (): void => {
104	    const newListener: ListenerForm = {
105	      hostname: '',
106	      port: '',
107	      name: '',
108	      protocol: protocols[0],
109	      isHostValid: false,
110	      from: allowedRoutes[0],
111	      isLabelSelectorValid: false,
112	      tlsMode: tlsModes[0],
113	      tlsCert: '',
114	      sSelectorLabels: ''
115	    };
116	
117	    const l = props.listenersForm;
118	    l.push(newListener);
119	
120	    const newListenerF: Listener = {
121	      hostname: '',
122	      port: 70000,
123	      name: '',
124	      protocol: protocols[0],
125	      allowedRoutes: { namespaces: { from: allowedRoutes[0] } }
126	    };
127	
128	    const lf = props.listeners;
129	    lf.push(newListenerF);
130	
131	    props.onChange(lf, l);
132	  };
133	
134	  const onRemoveListener = (index: number): void => {
135	    const l = props.listenersForm;
136	    l.splice(index, 1);
137	
138	    const lf = props.listeners;
139	    lf.splice(index, 1);
140	
141	    props.onChange(lf, l);
142	  };
143	
144	  const onChange = (listenersForm: ListenerForm, i: number): void => {
145	    const lf = props.listenersForm;
146	    lf[i] = listenersForm;
147	
148	    const l = props.listeners;
149	    const newL = createNewListener(listenersForm);
150	    if (typeof newL !== 'undefined') {
151	      l[i] = newL;
152	    }
153	
154	    props.onChange(l, lf);
155	  };
156	
157	  const createNewListener = (listenerForm: ListenerForm): Listener | undefined => {
158	    if (listenerForm.port.length === 0 || isNaN(Number(listenerForm.port))) return;
159	    if (listenerForm.hostname.length === 0) return;
160	
161	    const selector = addSelectorLabels(listenerForm.sSelectorLabels)[1] || {};
162	
163	    const listener: Listener = {
164	      hostname: listenerForm.hostname,
165	      port: Number(listenerForm.port),
166	      name: listenerForm.name,
167	      protocol: listenerForm.protocol,
168	      allowedRoutes: { namespaces: { from: listenerForm.from } }
169	    };
170	
171	    if (listenerForm.from === SELECTOR) {
172	      listener.allowedRoutes.namespaces.selector = { matchLabels: selector };
173	    }
174	
175	    if (protocolsCert.includes(listenerForm.protocol) && listenerForm.tlsMode === TERMINATE) {
176	      listener.tls = {
177	        certificateRefs: [
178	          {
179	            kind: 'Secret',
180	            name: listenerForm.tlsCert
181	          }
182	        ]
183	      };
184	    }
185	
186	    return listener;
187	  };
188	
189	  return (
190	    <>
191	      <Table aria-label="Listener List">
192	        <Thead>
193	          <Tr>
194	            {columns.map((column, index) => (
195	              <Th key={`column_${index}`} dataLabel={column.title} width={column.width}>
196	                {column.title}
197	              </Th>
198	            ))}
199	          </Tr>
200	        </Thead>
201	        <Tbody>
202	          {props.listenersForm.length > 0 ? (
203	            <>
204	              {props.listenersForm.map((listener, index) => (
205	                <ListenerBuilder
206	                  key={`listener_builder_${index}`}
207	                  listener={listener}
208	                  onRemoveListener={onRemoveListener}
209	                  index={index}
210	                  onChange={onChange}
211	                ></ListenerBuilder>
212	              ))}
213	            </>
214	          ) : (
215	            <Tr>
216	              <Td colSpan={columns.length}>
217	                <div className={noListenerStyle}>No Listeners defined</div>
218	              </Td>
219	            </Tr>
220	          )}
221	        </Tbody>
222	      </Table>
223	
224	      <Button
225	        name="addListener"
226	        variant={ButtonVariant.link}
227	        icon={<KialiIcon.AddMore />}
228	        onClick={onAddListener}
229	        className={addListenerStyle}
230	      >
231	        Add Listener to Listener List
232	      </Button>
233	    </>
234	  );
235	};

